const row = $input.item.json;

if (!row || !row.nome_requerente) {
  return null;
}

const cpf = row.cpf;
const consulta_id = row.consulta_id;
const current_state = row.current_state;
const whatsapp_from = row.whatsapp_from;
const nome_requerente = row.nome_requerente;
const email = row.email || 'não informado';
const erros_ocr = row.erros_ocr || null;

let lista_processos = [];
try {
  let processosObj = typeof row.processos === 'string'
    ? JSON.parse(row.processos)
    : row.processos;
  lista_processos = (processosObj.lista || []).map(p => p.numero);
} catch(e) {
  lista_processos = ['Não foi possível extrair os números dos processos'];
}

const processos_formatados_html = lista_processos.map(n => `<li>${n}</li>`).join('');

const msg_cliente = `Verificamos que o seu precatório tem documento escaneados ou com incompatibilidade de configuração no sistema do Tribunal de Justiça, motivo pelo qual o laudo será encaminhado em até 7 dias úteis em seu email`;

const detalhe_erro = erros_ocr
  ? `<p><strong>Erro OCR encontrado:</strong><br><code>${erros_ocr}</code></p>`
  : `<p><strong>Tipo de erro:</strong> <code>${current_state}</code> (sem detalhe de OCR disponível — verificar tabela logs)</p>`;

const msg_interna_html = `
  <p>CPF <strong>${cpf}</strong> — cliente <strong>${nome_requerente}</strong> não pôde ser processado automaticamente.</p>
  <p><strong>Estado atual:</strong> <code>${current_state}</code></p>
  <p><strong>Processos envolvidos:</strong></p>
  <ul>${processos_formatados_html}</ul>
  ${detalhe_erro}
  <p>Laudo a ser enviado ao email: <a href="mailto:${email}">${email}</a></p>
`;

const log_descricao = `🚨 Alerta erro grave enviado (${current_state}) - ALERTA_MANUAL_SENT`;
return { json: { cpf, consulta_id, current_state, whatsapp_from, nome_requerente, email, msg_cliente, msg_interna_html, log_descricao } };
